{
  "name": "EchoShift",
  "description": "A puzzle game where you cooperate with past versions of yourself. Master time loops, solve puzzles, and coordinate with your own echoes to escape."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT' | 'WAIT';

export interface Position {
  x: number;
  y: number;
}

export interface GameObject {
  id: string;
  type: 'WALL' | 'FLOOR' | 'SWITCH' | 'DOOR' | 'BLOCK' | 'LASER_EMITTER' | 'GOAL' | 'SPIKE';
  pos: Position;
  state?: any; // For door: isOpen, For laser: direction, etc.
  triggerId?: string; // ID of the object this interacts with (e.g. Switch -> Door)
  color?: string; // Optional override
}

export interface LevelData {
  id: number;
  name: string;
  description: string;
  gridWidth: number;
  gridHeight: number;
  loopDuration: number; // in milliseconds
  maxEchoes: number;
  startPos: Position;
  layout: GameObject[]; // Static and dynamic objects
}

export interface PlayerAction {
  tick: number;
  dir: Direction;
}

export interface GameState {
  levelId: number;
  status: 'IDLE' | 'PLAYING' | 'WON' | 'LOST';
  currentLoop: number;
  timeRemaining: number;
  tick: number;
  playerPos: Position;
  echoes: PlayerAction[][]; // Array of past action histories
  currentHistory: PlayerAction[];
  dynamicObjects: GameObject[]; // Blocks, Doors state
}

export const TILE_SIZE = 40;
export const TICK_RATE = 200; // ms per move tick
export const FRAME_RATE = 16; // 60fps for timer update

import { Direction, GameObject, Position, PlayerAction, LevelData } from '../types';

export const isPosEqual = (a: Position, b: Position) => a.x === b.x && a.y === b.y;

export const getNextPos = (pos: Position, dir: Direction): Position => {
  switch (dir) {
    case 'UP': return { x: pos.x, y: pos.y - 1 };
    case 'DOWN': return { x: pos.x, y: pos.y + 1 };
    case 'LEFT': return { x: pos.x - 1, y: pos.y };
    case 'RIGHT': return { x: pos.x + 1, y: pos.y };
    default: return pos;
  }
};

export const isValidMove = (
  target: Position,
  gridWidth: number,
  gridHeight: number,
  objects: GameObject[]
): boolean => {
  // Check bounds
  if (target.x < 0 || target.x >= gridWidth || target.y < 0 || target.y >= gridHeight) return false;

  // Check collision with static/solid objects
  const collider = objects.find(o => isPosEqual(o.pos, target));
  if (collider) {
    if (collider.type === 'WALL') return false;
    if (collider.type === 'DOOR' && !collider.state.isOpen) return false;
    if (collider.type === 'LASER_EMITTER') return false;
    // Blocks are handled separately via push logic
  }
  return true;
};

// Simulation Step
// We need to re-simulate the entire frame for all actors to ensure consistent interactions
export const simulateTick = (
  level: LevelData,
  playerAction: PlayerAction | undefined, // Current player's action
  echoActions: (PlayerAction | undefined)[], // Actions of all past echoes for this tick
  currentObjects: GameObject[],
  playerPos: Position,
  echoPositions: Position[]
): {
  nextPlayerPos: Position;
  nextEchoPositions: Position[];
  nextObjects: GameObject[];
  event: 'NONE' | 'WIN' | 'DEATH';
} => {
  let nextObjects = JSON.parse(JSON.stringify(currentObjects)) as GameObject[];
  let nextPlayerPos = { ...playerPos };
  let nextEchoPositions = [...echoPositions];
  let gameEvent: 'NONE' | 'WIN' | 'DEATH' = 'NONE';

  // Helper to find object at pos
  const findObject = (pos: Position) => nextObjects.find(o => isPosEqual(o.pos, pos));

  // 1. Process Movements (Player & Echoes)
  // We process them sequentially for simplicity. Ideally should be simultaneous but that's complex.
  // Priority: Echoes (oldest first), then Player. 

  // Combine all movers: Echoes first, then Player
  const movers = [
    ...echoActions.map((action, idx) => ({ 
      id: `echo-${idx}`, 
      isPlayer: false, 
      idx, 
      action, 
      currentPos: nextEchoPositions[idx] 
    })),
    { 
      id: 'player', 
      isPlayer: true, 
      idx: -1, 
      action: playerAction, 
      currentPos: nextPlayerPos 
    }
  ];

  // We need to track occupied positions for this tick to prevent overlaps
  // But for now, let's just check against objects and walls.
  // Echoes and Player can overlap (ghost mechanic) but usually bad for puzzle clarity.
  // Let's allow overlap for now to prevent "getting stuck in yourself", but collision with blocks is key.

  for (const mover of movers) {
    if (!mover.action || mover.action.dir === 'WAIT') continue;

    const targetPos = getNextPos(mover.currentPos, mover.action.dir);

    // Check bounds & walls
    if (!isValidMove(targetPos, level.gridWidth, level.gridHeight, nextObjects)) {
      continue; // Blocked
    }

    // Check interaction with dynamic objects (Block Push)
    const objAtTarget = findObject(targetPos);
    if (objAtTarget && objAtTarget.type === 'BLOCK') {
      // Try to push block
      const blockTarget = getNextPos(targetPos, mover.action.dir);
      // Check if block can move
      // Block cannot move into another block, wall, or closed door
      // AND block cannot move into any other actor? (Simplification: ignore actor collision for blocks for now)
      if (isValidMove(blockTarget, level.gridWidth, level.gridHeight, nextObjects) && !findObject(blockTarget)) {
         // Move block
         objAtTarget.pos = blockTarget;
         // Move actor
         if (mover.isPlayer) nextPlayerPos = targetPos;
         else nextEchoPositions[mover.idx] = targetPos;
      }
    } else {
      // Just move
      if (mover.isPlayer) nextPlayerPos = targetPos;
      else nextEchoPositions[mover.idx] = targetPos;
    }
  }

  // 2. Update Switches & Doors
  // Check all switches
  const switches = nextObjects.filter(o => o.type === 'SWITCH');
  const allActorPositions = [nextPlayerPos, ...nextEchoPositions];

  // Also include blocks in "actors" that can press switches
  const blocks = nextObjects.filter(o => o.type === 'BLOCK');
  const allPressers = [...allActorPositions, ...blocks.map(b => b.pos)];

  switches.forEach(sw => {
    const isPressed = allPressers.some(p => isPosEqual(p, sw.pos));

    // Find linked door
    if (sw.triggerId) {
      const door = nextObjects.find(d => d.id === sw.triggerId);
      if (door && door.type === 'DOOR') {
        door.state.isOpen = isPressed;
      }
    }
  });

  // 3. Check Lasers
  const lasers = nextObjects.filter(o => o.type === 'LASER_EMITTER');
  let laserHazardPositions: Position[] = [];

  lasers.forEach(laser => {
    let beamPos = getNextPos(laser.pos, laser.state.dir);
    let safety = 0;
    while (safety < 20) { // Max range to prevent infinite
      if (beamPos.x < 0 || beamPos.x >= level.gridWidth || beamPos.y < 0 || beamPos.y >= level.gridHeight) break;

      const hitObj = findObject(beamPos);
      if (hitObj && (hitObj.type === 'WALL' || hitObj.type === 'BLOCK' || (hitObj.type === 'DOOR' && !hitObj.state.isOpen))) {
        break; // Laser stopped
      }

      // Check if any echo is blocking the laser?
      // "Echoes can block lasers" - interpreted as solid to laser
      const echoBlocking = nextEchoPositions.some(e => isPosEqual(e, beamPos));
      if (echoBlocking) {
        break; // Laser stopped by Echo body
      }

      laserHazardPositions.push(beamPos);
      beamPos = getNextPos(beamPos, laser.state.dir);
      safety++;
    }
  });

  // 4. Check Win/Loss

  // Death by Laser
  if (laserHazardPositions.some(p => isPosEqual(p, nextPlayerPos))) {
    gameEvent = 'DEATH';
  }

  // Win by Goal
  const goal = nextObjects.find(o => o.type === 'GOAL');
  if (goal && isPosEqual(nextPlayerPos, goal.pos)) {
    gameEvent = 'WIN';
  }

  return {
    nextPlayerPos,
    nextEchoPositions,
    nextObjects,
    event: gameEvent
  };
};

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { GameObject, Position, TILE_SIZE, LevelData } from '../types';
import { User, Copy, Lock, Unlock, Zap, Box, Flag, CircleDot } from 'lucide-react';

interface GameCanvasProps {
  level: LevelData;
  playerPos: Position;
  echoes: Position[];
  objects: GameObject[];
  width: number;
  height: number;
}

const getTileColor = (x: number, y: number) => {
  return (x + y) % 2 === 0 ? 'bg-slate-800/50' : 'bg-slate-800/30';
};

const GameCanvas: React.FC<GameCanvasProps> = ({ level, playerPos, echoes, objects, width, height }) => {

  // Helper to render grid
  const renderGrid = () => {
    const tiles = [];
    for (let y = 0; y < height; y++) {
      for (let x = 0; x < width; x++) {
        tiles.push(
          <div
            key={`${x}-${y}`}
            className={`absolute border-slate-700/20 border ${getTileColor(x, y)}`}
            style={{
              width: TILE_SIZE,
              height: TILE_SIZE,
              left: x * TILE_SIZE,
              top: y * TILE_SIZE,
            }}
          />
        );
      }
    }
    return tiles;
  };

  const renderObjects = () => {
    return objects.map(obj => {
      let Content = null;
      let styleClass = '';

      switch (obj.type) {
        case 'WALL':
          styleClass = 'bg-slate-600 border border-slate-500 shadow-lg';
          break;
        case 'GOAL':
          Content = <Flag className="text-cyan-400 w-6 h-6 animate-pulse" />;
          styleClass = 'bg-cyan-900/30 border border-cyan-500/50 shadow-[0_0_15px_rgba(34,211,238,0.3)]';
          break;
        case 'BLOCK':
          Content = <Box className="text-amber-200 w-6 h-6" />;
          styleClass = 'bg-amber-700 border border-amber-500 shadow-md z-10';
          break;
        case 'SWITCH':
          const isActive = false; // Visual only, logic handled in engine. We could pass active state if needed.
          Content = <CircleDot className={`w-5 h-5 ${obj.color === 'purple' ? 'text-purple-400' : 'text-amber-400'}`} />;
          styleClass = 'bg-slate-900/80 border border-slate-700 z-0 scale-75 rounded-full';
          break;
        case 'DOOR':
           // Use obj.state.isOpen
           const isOpen = obj.state?.isOpen;
           Content = isOpen ? <Unlock className="w-5 h-5 opacity-50" /> : <Lock className="w-5 h-5" />;
           styleClass = isOpen 
            ? `bg-slate-900/20 border-2 border-dashed ${obj.color === 'purple' ? 'border-purple-900/50 text-purple-900' : 'border-amber-900/50 text-amber-900'} opacity-50 z-10` 
            : `bg-slate-900 border-2 ${obj.color === 'purple' ? 'border-purple-500 text-purple-400' : 'border-amber-500 text-amber-400'} shadow-lg z-10`;
           break;
        case 'LASER_EMITTER':
           Content = <Zap className="w-4 h-4 text-red-500 fill-red-500" />;
           styleClass = 'bg-slate-800 border border-slate-600 z-10';
           break;
      }

      return (
        <motion.div
          key={obj.id}
          initial={false}
          animate={{ x: obj.pos.x * TILE_SIZE, y: obj.pos.y * TILE_SIZE }}
          transition={{ type: "spring", stiffness: 300, damping: 25 }}
          className={`absolute flex items-center justify-center rounded-md ${styleClass}`}
          style={{ width: TILE_SIZE, height: TILE_SIZE }}
        >
          {Content}
        </motion.div>
      );
    });
  };

  const renderLasers = () => {
    const beams: JSX.Element[] = [];
    objects.filter(o => o.type === 'LASER_EMITTER').forEach(emitter => {
        // Simple raycast visualization matching engine logic
        // We re-calculate here purely for visuals. 
        // In a real optimized game, engine should pass beam segments.
        let bx = emitter.pos.x;
        let by = emitter.pos.y;
        const dx = emitter.state.dir === 'RIGHT' ? 1 : emitter.state.dir === 'LEFT' ? -1 : 0;
        const dy = emitter.state.dir === 'DOWN' ? 1 : emitter.state.dir === 'UP' ? -1 : 0;

        // Advance once to start
        bx += dx; by += dy;

        for(let i=0; i<20; i++) {
           if(bx < 0 || bx >= width || by < 0 || by >= height) break;

           // Check collision visually
           const hitObj = objects.find(o => o.pos.x === bx && o.pos.y === by);
           // Echo collision check?
           const echoHit = echoes.some(e => e.x === bx && e.y === by);

           // Draw beam segment
           const isHorizontal = dy === 0;
           beams.push(
             <motion.div
               key={`beam-${emitter.id}-${i}`}
               initial={{ opacity: 0 }}
               animate={{ opacity: 1 }}
               className="absolute bg-red-500 shadow-[0_0_8px_#ef4444] z-0 pointer-events-none"
               style={{
                 left: bx * TILE_SIZE + (isHorizontal ? 0 : TILE_SIZE/2 - 2),
                 top: by * TILE_SIZE + (isHorizontal ? TILE_SIZE/2 - 2 : 0),
                 width: isHorizontal ? TILE_SIZE : 4,
                 height: isHorizontal ? 4 : TILE_SIZE,
               }}
             />
           );

           if(hitObj && (hitObj.type === 'WALL' || hitObj.type === 'BLOCK' || (hitObj.type === 'DOOR' && !hitObj.state.isOpen))) break;
           if(echoHit) break; 

           bx += dx; by += dy;
        }
    });
    return beams;
  };

  return (
    <div 
      className="relative bg-slate-900 rounded-lg shadow-2xl overflow-hidden border-2 border-slate-700"
      style={{ width: width * TILE_SIZE, height: height * TILE_SIZE }}
    >
      {renderGrid()}
      {renderObjects()}
      {renderLasers()}

      {/* Echoes */}
      <AnimatePresence>
        {echoes.map((pos, idx) => (
          <motion.div
            key={`echo-${idx}`}
            initial={{ opacity: 0, scale: 0 }}
            animate={{ opacity: 0.6, scale: 1, x: pos.x * TILE_SIZE, y: pos.y * TILE_SIZE }}
            exit={{ opacity: 0, scale: 0 }}
            transition={{ type: "spring", stiffness: 200, damping: 20 }}
            className="absolute flex items-center justify-center z-10"
            style={{ width: TILE_SIZE, height: TILE_SIZE }}
          >
            <div className="w-8 h-8 bg-purple-500/30 rounded-full flex items-center justify-center border border-purple-400 shadow-[0_0_10px_#a855f7]">
               <Copy className="w-5 h-5 text-purple-200" />
            </div>
            <div className="absolute -top-3 -right-3 text-[10px] font-bold text-purple-300 bg-slate-900 px-1 rounded">E{idx+1}</div>
          </motion.div>
        ))}
      </AnimatePresence>

      {/* Player */}
      <motion.div
        animate={{ x: playerPos.x * TILE_SIZE, y: playerPos.y * TILE_SIZE }}
        transition={{ type: "spring", stiffness: 300, damping: 25 }}
        className="absolute flex items-center justify-center z-20"
        style={{ width: TILE_SIZE, height: TILE_SIZE }}
      >
        <div className="w-8 h-8 bg-cyan-500/80 rounded-full flex items-center justify-center border-2 border-cyan-300 shadow-[0_0_15px_#22d3ee]">
          <User className="w-5 h-5 text-white" />
        </div>
      </motion.div>

    </div>
  );
};

export default GameCanvas;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Play, RotateCw, Clock, SkipForward, AlertCircle, Info, Trophy, Skull } from 'lucide-react';
import GameCanvas from './components/GameCanvas';
import { LEVELS } from './levels';
import { LevelData, GameState, PlayerAction, Position, Direction, TICK_RATE } from './types';
import { simulateTick } from './utils/gameLogic';

const App: React.FC = () => {
  const [currentLevelIdx, setCurrentLevelIdx] = useState(0);
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [inputQueue, setInputQueue] = useState<Direction>('WAIT');

  // Logic Refs for stability in Interval
  const stateRef = useRef<GameState | null>(null);
  const lastTickTime = useRef<number>(0);

  // Initialize Level
  const initLevel = useCallback((levelIndex: number) => {
    const level = LEVELS[levelIndex];
    const initialState: GameState = {
      levelId: level.id,
      status: 'IDLE',
      currentLoop: 1,
      timeRemaining: level.loopDuration,
      tick: 0,
      playerPos: { ...level.startPos },
      echoes: [], // Array of history arrays
      currentHistory: [],
      dynamicObjects: JSON.parse(JSON.stringify(level.layout)),
    };
    setGameState(initialState);
    stateRef.current = initialState;
    setInputQueue('WAIT');
  }, []);

  useEffect(() => {
    initLevel(0);
  }, [initLevel]);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!gameState || gameState.status !== 'PLAYING') return;

      switch (e.key) {
        case 'ArrowUp': 
        case 'w':
        case 'W':
            setInputQueue('UP'); break;
        case 'ArrowDown':
        case 's':
        case 'S':
            setInputQueue('DOWN'); break;
        case 'ArrowLeft':
        case 'a':
        case 'A':
            setInputQueue('LEFT'); break;
        case 'ArrowRight':
        case 'd':
        case 'D':
            setInputQueue('RIGHT'); break;
        case ' ': // Space to wait
            setInputQueue('WAIT'); break;
        case 'r':
        case 'R':
            initLevel(currentLevelIdx); break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [gameState, currentLevelIdx, initLevel]);

  // Core Game Loop
  useEffect(() => {
    if (!gameState || gameState.status !== 'PLAYING') return;

    const gameLoop = setInterval(() => {
      const now = Date.now();
      const currentState = stateRef.current;
      if (!currentState || currentState.status !== 'PLAYING') return;

      // 1. Check Time Loop End
      if (currentState.timeRemaining <= 0) {
        handleLoopEnd(currentState);
        return;
      }

      // 2. Process Tick Logic (Movement) only every TICK_RATE
      if (now - lastTickTime.current >= TICK_RATE) {
        processTick(currentState);
        lastTickTime.current = now;
      }

      // 3. Update Time High-Freq
      setGameState(prev => {
        if (!prev) return null;
        const newState = { 
          ...prev, 
          timeRemaining: Math.max(0, prev.timeRemaining - 50) 
        };
        stateRef.current = newState;
        return newState;
      });

    }, 50);

    return () => clearInterval(gameLoop);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [gameState?.status]);

  const processTick = (state: GameState) => {
    const level = LEVELS[currentLevelIdx];

    // Get current action
    const action: PlayerAction = { tick: state.tick, dir: inputQueue };
    // Consume input
    setInputQueue('WAIT');

    // Get echo actions for this tick
    const echoActions = state.echoes.map(history => history[state.tick]);

    // Current Echo Positions (calculated from previous tick or initialization)
    // NOTE: In a robust engine, we'd store echo positions in state. 
    // To save state complexity, we'll recalculate or store transiently.
    // For this implementation, let's assume we need to re-simulate everything from T=0? 
    // No, that's too expensive. 
    // We need to store Echo Positions in state.
    // Let's add echoPositions to component state? Or derived?
    // Let's just store "Echo Positions" in a transient ref for the simulation loop?
    // Actually, `simulateTick` returns next positions. We should store them.
    // However, `GameState` doesn't strictly track echo positions in the main object to keep it clean, 
    // but we need them for rendering and collision.
    // Solution: Let's add `echoPositions` to the state to be safe.

    // Hack: We need the PREVIOUS positions of echoes.
    // Since we don't store them in GameState explicitly in the simplified type earlier, let's infer them?
    // Better: Extend GameState to hold `currentEchoPositions`.

    // *Self-Correction*: I'll add `currentEchoPositions` to state logic locally here or extend the type. 
    // Extending type is cleaner but I can't edit `types.ts` again easily in this flow without breaking XML structure order if not careful.
    // I will compute them on the fly? No, they depend on history.
    // Let's assume for the very first tick, echoes are at StartPos.
    // We need to store them. I will use a ref for `echoPositions` to persist between ticks without causing re-renders, 
    // but we need re-renders to show them moving.
    // Let's attach them to the `dynamicObjects` or a separate state.

    // Let's use a Ref for "Current Tick Echo Positions" initialized at loop start.
  };

  // Re-implementing processTick with State-managed Echo Positions
  // We need to modify GameState in `initLevel` to include `echoPos`.
  // Since I can't change `types.ts` now, I'll augment it in the `useState`.
  // Actually, I can use a separate state `echoPositions`.

  const [echoPositions, setEchoPositions] = useState<Position[]>([]);

  const handleLoopEnd = (state: GameState) => {
    const level = LEVELS[currentLevelIdx];

    if (state.echoes.length >= level.maxEchoes) {
      setGameState({ ...state, status: 'LOST' });
      return;
    }

    // Save current run
    const newEchoes = [...state.echoes, state.currentHistory];

    // Reset
    const nextState: GameState = {
      ...state,
      currentLoop: state.currentLoop + 1,
      timeRemaining: level.loopDuration,
      tick: 0,
      playerPos: { ...level.startPos },
      echoes: newEchoes,
      currentHistory: [],
      dynamicObjects: JSON.parse(JSON.stringify(level.layout)), // Reset world objects
    };

    setGameState(nextState);
    stateRef.current = nextState;
    setEchoPositions(newEchoes.map(() => ({ ...level.startPos }))); // Reset echoes to start
    setInputQueue('WAIT');
  };

  const processTickRefined = (state: GameState) => {
    const level = LEVELS[currentLevelIdx];

    // Current Input
    const currentAction: PlayerAction = { tick: state.tick, dir: inputQueue };
    setInputQueue('WAIT'); // Reset input buffer

    // Echo Inputs
    const currentEchoActions = state.echoes.map(hist => hist[state.tick]);

    // Current Echo Positions (from state or init)
    const currentEchoPos = echoPositions.length === state.echoes.length 
        ? echoPositions 
        : state.echoes.map(() => ({ ...level.startPos }));

    // SIMULATE
    const result = simulateTick(
      level,
      currentAction,
      currentEchoActions,
      state.dynamicObjects,
      state.playerPos,
      currentEchoPos
    );

    // Update State
    if (result.event === 'WIN') {
        setGameState(prev => prev ? { ...prev, status: 'WON' } : null);
    } else if (result.event === 'DEATH') {
        // Instant Loop Reset or Game Over? 
        // Let's just force loop end early? Or Game Over?
        // Prompt says "Failure occurs if... Player collides...".
        // Let's make it a strict fail for this loop, or total fail?
        // Usually puzzle games restart the loop.
        // Let's trigger loop end immediately but invalidate the run? 
        // Simplest: Game Over, try again.
        setGameState(prev => prev ? { ...prev, status: 'LOST' } : null);
    } else {
        const nextState: GameState = {
            ...state,
            tick: state.tick + 1,
            playerPos: result.nextPlayerPos,
            dynamicObjects: result.nextObjects,
            currentHistory: [...state.currentHistory, currentAction]
        };
        setGameState(nextState);
        stateRef.current = nextState;
        setEchoPositions(result.nextEchoPositions);
    }
  };

  // Override the interval to use the refined tick
  useEffect(() => {
    if (!gameState || gameState.status !== 'PLAYING') return;

    const gameLoop = setInterval(() => {
      const now = Date.now();
      const currentState = stateRef.current;
      if (!currentState || currentState.status !== 'PLAYING') return;

      if (currentState.timeRemaining <= 0) {
        handleLoopEnd(currentState);
        return;
      }

      if (now - lastTickTime.current >= TICK_RATE) {
        processTickRefined(currentState);
        lastTickTime.current = now;
      } else {
        // High freq timer update
        setGameState(prev => {
            if (!prev) return null;
            const ns = { ...prev, timeRemaining: Math.max(0, prev.timeRemaining - (now - (lastTickTime.current || now)) ) }; 
            // Rough timer approximation for smooth UI, usually we'd use delta
            // Better: just decrement by interval
            return { ...prev, timeRemaining: Math.max(0, currentState.timeRemaining - 16) };
        });
      }

    }, 16);

    return () => clearInterval(gameLoop);
  }, [gameState?.status]);


  // ---- Render Helpers ----

  const formatTime = (ms: number) => (ms / 1000).toFixed(1);

  const level = LEVELS[currentLevelIdx];

  return (
