           <div className="flex gap-4 text-sm font-medium text-slate-400">
             <span className="flex items-center gap-1"><RotateCw size={14}/> Loop {gameState?.currentLoop || 1} / {level.maxEchoes + 1}</span>
             <span className="flex items-center gap-1 text-cyan-400"><Clock size={14}/> {formatTime(gameState?.timeRemaining || level.loopDuration)}s</span>
           </div>
        </div>
        <div className="text-right">
            <h2 className="text-xl font-bold text-slate-100">{level.id}. {level.name}</h2>
            <p className="text-slate-500 text-sm">{level.description}</p>
        </div>
      </div>

      {/* Game Area */}
      <div className="relative group">

        {/* Canvas */}
        <GameCanvas 
          level={level}
          width={level.gridWidth}
          height={level.gridHeight}
          objects={gameState?.dynamicObjects || level.layout}
          playerPos={gameState?.playerPos || level.startPos}
          echoes={echoPositions}
        />

        {/* Overlays */}
        {gameState?.status === 'IDLE' && (
          <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm flex flex-col items-center justify-center z-50">
             <button 
                onClick={() => setGameState({ ...gameState!, status: 'PLAYING' })}
                className="bg-cyan-600 hover:bg-cyan-500 text-white px-8 py-3 rounded-full font-bold shadow-[0_0_20px_rgba(8,145,178,0.5)] flex items-center gap-2 transition-transform hover:scale-105"
             >
                <Play size={20} fill="currentColor" /> INITIATE LINK
             </button>
             <p className="mt-4 text-slate-400 text-sm">Use Arrow Keys or WASD to move</p>
          </div>
        )}

        {gameState?.status === 'WON' && (
          <div className="absolute inset-0 bg-green-900/90 backdrop-blur-md flex flex-col items-center justify-center z-50 animate-in fade-in duration-300">
             <Trophy size={64} className="text-yellow-400 mb-4 drop-shadow-[0_0_15px_rgba(250,204,21,0.5)]" />
             <h2 className="text-3xl font-bold text-white mb-2">SEQUENCE COMPLETE</h2>
             <p className="text-green-200 mb-6">Timeline stabilized.</p>
             <div className="flex gap-4">
               {currentLevelIdx < LEVELS.length - 1 ? (
                 <button 
                    onClick={() => {
