import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Play, RotateCw, Clock, SkipForward, Trophy, Skull, ChevronUp, ChevronDown, ChevronLeft, ChevronRight, Circle, RefreshCw } from 'lucide-react';
import GameCanvas from './components/GameCanvas';
import { LEVELS } from './levels';
import { GameState, PlayerAction, Position, Direction, TICK_RATE, TILE_SIZE } from './types';
import { simulateTick } from './utils/gameLogic';

const App: React.FC = () => {
  const [currentLevelIdx, setCurrentLevelIdx] = useState(0);
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [echoPositions, setEchoPositions] = useState<Position[]>([]);
  const [scale, setScale] = useState(1);

  // Logic Refs for stability in Interval - These hold the "Real" values for the game loop
  const stateRef = useRef<GameState | null>(null);
  const inputQueueRef = useRef<Direction>('WAIT');
  const echoPositionsRef = useRef<Position[]>([]);
  const lastTickTime = useRef<number>(0);
  const containerRef = useRef<HTMLDivElement>(null);

  // Initialize Level
  const initLevel = useCallback((levelIndex: number) => {
    const level = LEVELS[levelIndex];
    const initialState: GameState = {
      levelId: level.id,
      status: 'IDLE',
      currentLoop: 1,
      timeRemaining: level.loopDuration,
      tick: 0,
      playerPos: { ...level.startPos },
      echoes: [], // Array of history arrays
      currentHistory: [],
      dynamicObjects: JSON.parse(JSON.stringify(level.layout)),
    };

    // Reset React State
    setGameState(initialState);
    setEchoPositions([]);

    // Reset Refs
    stateRef.current = initialState;
    inputQueueRef.current = 'WAIT';
    echoPositionsRef.current = [];
  }, []);

  useEffect(() => {
    initLevel(0);
  }, [initLevel]);

  // Handle Window Resize for Scaling
  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current) {
        const level = LEVELS[currentLevelIdx];
        const neededWidth = level.gridWidth * TILE_SIZE + 32; // + padding
        const availableWidth = window.innerWidth;

        if (availableWidth < neededWidth) {
          setScale(availableWidth / neededWidth);
        } else {
          setScale(1);
        }
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize(); // Initial call
    return () => window.removeEventListener('resize', handleResize);
  }, [currentLevelIdx]);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!stateRef.current || stateRef.current.status !== 'PLAYING') return;

      switch (e.key) {
        case 'ArrowUp': 
        case 'w':
        case 'W':
            inputQueueRef.current = 'UP'; break;
        case 'ArrowDown':
        case 's':
        case 'S':
            inputQueueRef.current = 'DOWN'; break;
        case 'ArrowLeft':
        case 'a':
        case 'A':
            inputQueueRef.current = 'LEFT'; break;
        case 'ArrowRight':
        case 'd':
        case 'D':
            inputQueueRef.current = 'RIGHT'; break;
        case ' ': // Space to wait
            inputQueueRef.current = 'WAIT'; break;
        case 'r':
        case 'R':
            initLevel(currentLevelIdx); break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentLevelIdx, initLevel]);

  const handleInput = (dir: Direction) => {
     if (navigator.vibrate) navigator.vibrate(10); // Subtle haptic feedback
     inputQueueRef.current = dir;
  };

  const handleLoopEnd = (state: GameState) => {
    const level = LEVELS[currentLevelIdx];

    if (state.echoes.length >= level.maxEchoes) {
      setGameState({ ...state, status: 'LOST' });
      return;
    }

    // Save current run
    const newEchoes = [...state.echoes, state.currentHistory];

    // Reset
    const nextState: GameState = {
      ...state,
      currentLoop: state.currentLoop + 1,
      timeRemaining: level.loopDuration,
      tick: 0,
      playerPos: { ...level.startPos },
      echoes: newEchoes,
      currentHistory: [],
      dynamicObjects: JSON.parse(JSON.stringify(level.layout)), // Reset world objects
    };

    setGameState(nextState);
    stateRef.current = nextState;

    // Reset Echo positions to start for the new loop
    const startPositions = newEchoes.map(() => ({ ...level.startPos }));
    setEchoPositions(startPositions);
    echoPositionsRef.current = startPositions;

    inputQueueRef.current = 'WAIT';
  };

  const processTick = (state: GameState) => {
    const level = LEVELS[currentLevelIdx];

    // Current Input from Ref
    const currentAction: PlayerAction = { tick: state.tick, dir: inputQueueRef.current };
    inputQueueRef.current = 'WAIT'; // Reset input buffer

    // Echo Inputs
    const currentEchoActions = state.echoes.map(hist => hist[state.tick]);

    // Current Echo Positions (from Ref)
    // If ref is empty but we have echoes, init them
    let currentEchoPos = echoPositionsRef.current;
    if (currentEchoPos.length !== state.echoes.length) {
        currentEchoPos = state.echoes.map(() => ({ ...level.startPos }));
    }

    // SIMULATE
    const result = simulateTick(
      level,
      currentAction,
      currentEchoActions,
      state.dynamicObjects,
      state.playerPos,
      currentEchoPos
    );

    // Update Refs & State
    if (result.event === 'WIN') {
        setGameState(prev => prev ? { ...prev, status: 'WON' } : null);
        stateRef.current = { ...state, status: 'WON' };
    } else if (result.event === 'DEATH') {
        setGameState(prev => prev ? { ...prev, status: 'LOST' } : null);
        stateRef.current = { ...state, status: 'LOST' };
    } else {
        const nextState: GameState = {
            ...state,
            tick: state.tick + 1,
            playerPos: result.nextPlayerPos,
            dynamicObjects: result.nextObjects,
            currentHistory: [...state.currentHistory, currentAction]
        };

        // Update Refs
        stateRef.current = nextState;
        echoPositionsRef.current = result.nextEchoPositions;

        // Update React State (triggers render)
        setGameState(nextState);
        setEchoPositions(result.nextEchoPositions);
    }
  };

  // Core Game Loop
  useEffect(() => {
    // We only want to start the interval if status is PLAYING.
    // However, we need to be careful not to trap stale closures.
    // By using Refs for everything inside the interval, we are safe.

    const gameLoop = setInterval(() => {
      const now = Date.now();
      const currentState = stateRef.current;

      // Guard clauses
      if (!currentState || currentState.status !== 'PLAYING') return;

      // 1. Check Loop End
      if (currentState.timeRemaining <= 0) {
        handleLoopEnd(currentState);
        return;
      }

      // 2. Process Game Tick (Movement)
      if (now - lastTickTime.current >= TICK_RATE) {
        processTick(currentState);
        lastTickTime.current = now;
      } 
      // 3. Update Timer (Visual only)
      else {
        // We update state directly for smooth UI, but logic relies on Ref
        setGameState(prev => {
            if (!prev) return null;
            const nextTime = Math.max(0, prev.timeRemaining - 16);
            const nextState = { ...prev, timeRemaining: nextTime };
            stateRef.current = nextState; // Keep ref in sync
            return nextState;
        });
      }

    }, 16);

    return () => clearInterval(gameLoop);
  }, [gameState?.status]); // Re-create loop if status changes (e.g. IDLE -> PLAYING)


  // ---- Render Helpers ----

  const formatTime = (ms: number) => (ms / 1000).toFixed(1);

  const level = LEVELS[currentLevelIdx];

  // Mobile Control Button Component
  const ControlBtn = ({ dir, icon: Icon, color = "bg-slate-800" }: { dir?: Direction, icon: any, color?: string }) => (
    <button
      className={`${color} w-14 h-14 rounded-full flex items-center justify-center shadow-lg active:scale-95 active:bg-cyan-900 transition-all border border-slate-600`}
      onPointerDown={(e) => {
        e.preventDefault(); 
        if (dir) handleInput(dir);
      }}
    >
      <Icon className="text-slate-200 w-8 h-8" />
    </button>
  );

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 flex flex-col items-center justify-center p-4 touch-none select-none">

      {/* Header */}
      <div className="w-full max-w-4xl flex flex-col md:flex-row justify-between items-center md:items-end mb-4 md:mb-6">
        <div className="text-center md:text-left mb-2 md:mb-0">
           <h1 className="text-3xl md:text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-purple-500 mb-2">
             ECHOSHIFT
           </h1>
           <div className="flex justify-center md:justify-start gap-4 text-sm font-medium text-slate-400">
             <span className="flex items-center gap-1"><RotateCw size={14}/> Loop {gameState?.currentLoop || 1} / {level.maxEchoes + 1}</span>
             <span className="flex items-center gap-1 text-cyan-400"><Clock size={14}/> {formatTime(gameState?.timeRemaining || level.loopDuration)}s</span>
           </div>
        </div>
        <div className="text-center md:text-right">
            <h2 className="text-lg md:text-xl font-bold text-slate-100">{level.id}. {level.name}</h2>
            <p className="text-slate-500 text-xs md:text-sm max-w-xs">{level.description}</p>
        </div>
      </div>

      {/* Game Area Container for Scaling */}
      <div 
        ref={containerRef}
        className="relative group flex items-center justify-center"
        style={{ 
          width: level.gridWidth * TILE_SIZE, 
          height: level.gridHeight * TILE_SIZE,
