  // Logic Refs for stability in Interval - These hold the "Real" values for the game loop
  const stateRef = useRef<GameState | null>(null);
  const inputQueueRef = useRef<Direction>('WAIT');
  const echoPositionsRef = useRef<Position[]>([]);
  const lastTickTime = useRef<number>(0);
  const containerRef = useRef<HTMLDivElement>(null);

