  // Handle Window Resize for Scaling
  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current) {
        const level = LEVELS[currentLevelIdx];
        const neededWidth = level.gridWidth * TILE_SIZE + 32; // + padding
        const availableWidth = window.innerWidth;

        if (availableWidth < neededWidth) {
          setScale(availableWidth / neededWidth);
        } else {
          setScale(1);
        }
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize(); // Initial call
    return () => window.removeEventListener('resize', handleResize);
  }, [currentLevelIdx]);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!stateRef.current || stateRef.current.status !== 'PLAYING') return;

      switch (e.key) {
        case 'ArrowUp': 
        case 'w':
        case 'W':
            inputQueueRef.current = 'UP'; break;
        case 'ArrowDown':
        case 's':
        case 'S':
            inputQueueRef.current = 'DOWN'; break;
        case 'ArrowLeft':
        case 'a':
        case 'A':
            inputQueueRef.current = 'LEFT'; break;
        case 'ArrowRight':
        case 'd':
        case 'D':
            inputQueueRef.current = 'RIGHT'; break;
        case ' ': // Space to wait
            inputQueueRef.current = 'WAIT'; break;
        case 'r':
        case 'R':
            initLevel(currentLevelIdx); break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentLevelIdx, initLevel]);

  const handleInput = (dir: Direction) => {
     if (navigator.vibrate) navigator.vibrate(10); // Subtle haptic feedback
     inputQueueRef.current = dir;
  };

  const handleLoopEnd = (state: GameState) => {
    const level = LEVELS[currentLevelIdx];

    if (state.echoes.length >= level.maxEchoes) {
      setGameState({ ...state, status: 'LOST' });
      return;
    }

    // Save current run
    const newEchoes = [...state.echoes, state.currentHistory];

    // Reset
    const nextState: GameState = {
      ...state,
      currentLoop: state.currentLoop + 1,
      timeRemaining: level.loopDuration,
      tick: 0,
      playerPos: { ...level.startPos },
      echoes: newEchoes,
      currentHistory: [],
      dynamicObjects: JSON.parse(JSON.stringify(level.layout)), // Reset world objects
    };

    setGameState(nextState);
    stateRef.current = nextState;

    // Reset Echo positions to start for the new loop
    const startPositions = newEchoes.map(() => ({ ...level.startPos }));
    setEchoPositions(startPositions);
    echoPositionsRef.current = startPositions;

    inputQueueRef.current = 'WAIT';
  };

  const processTick = (state: GameState) => {
    const level = LEVELS[currentLevelIdx];

    // Current Input from Ref
    const currentAction: PlayerAction = { tick: state.tick, dir: inputQueueRef.current };
    inputQueueRef.current = 'WAIT'; // Reset input buffer

    // Echo Inputs
    const currentEchoActions = state.echoes.map(hist => hist[state.tick]);

    // Current Echo Positions (from Ref)
    // If ref is empty but we have echoes, init them
    let currentEchoPos = echoPositionsRef.current;
    if (currentEchoPos.length !== state.echoes.length) {
        currentEchoPos = state.echoes.map(() => ({ ...level.startPos }));
    }

    // SIMULATE
    const result = simulateTick(
      level,
      currentAction,
      currentEchoActions,
      state.dynamicObjects,
      state.playerPos,
      currentEchoPos
    );

    // Update Refs & State
    if (result.event === 'WIN') {
        setGameState(prev => prev ? { ...prev, status: 'WON' } : null);
        stateRef.current = { ...state, status: 'WON' };
    } else if (result.event === 'DEATH') {
        setGameState(prev => prev ? { ...prev, status: 'LOST' } : null);
        stateRef.current = { ...state, status: 'LOST' };
    } else {
        const nextState: GameState = {
            ...state,
            tick: state.tick + 1,
            playerPos: result.nextPlayerPos,
            dynamicObjects: result.nextObjects,
            currentHistory: [...state.currentHistory, currentAction]
        };

        // Update Refs
        stateRef.current = nextState;
        echoPositionsRef.current = result.nextEchoPositions;

        // Update React State (triggers render)
        setGameState(nextState);
        setEchoPositions(result.nextEchoPositions);
    }
  };

  // Core Game Loop
  useEffect(() => {
    // We only want to start the interval if status is PLAYING.
    // However, we need to be careful not to trap stale closures.
    // By using Refs for everything inside the interval, we are safe.

    const gameLoop = setInterval(() => {
      const now = Date.now();
      const currentState = stateRef.current;

      // Guard clauses
      if (!currentState || currentState.status !== 'PLAYING') return;

      // 1. Check Loop End
      if (currentState.timeRemaining <= 0) {
        handleLoopEnd(currentState);
        return;
      }

      // 2. Process Game Tick (Movement)
      if (now - lastTickTime.current >= TICK_RATE) {
        processTick(currentState);
        lastTickTime.current = now;
      } 
      // 3. Update Timer (Visual only)
      else {
        // We update state directly for smooth UI, but logic relies on Ref
        setGameState(prev => {
            if (!prev) return null;
            const nextTime = Math.max(0, prev.timeRemaining - 16);
            const nextState = { ...prev, timeRemaining: nextTime };
            stateRef.current = nextState; // Keep ref in sync
            return nextState;
        });
      }

    }, 16);

    return () => clearInterval(gameLoop);
  }, [gameState?.status]); // Re-create loop if status changes (e.g. IDLE -> PLAYING)


  // Hint Generation
  const fetchHint = async () => {
    setShowHint(true);
    if (hintText) return;

    setLoadingHint(true);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const level = LEVELS[currentLevelIdx];

        const prompt = `
            You are an expert player of the puzzle game "EchoShift".

            LEVEL INFO:
            Name: ${level.name}
            Description: ${level.description}
            Grid Size: ${level.gridWidth}x${level.gridHeight}
            Max Loops: ${level.maxEchoes + 1}
            Layout JSON: ${JSON.stringify(level.layout)}

            GAME RULES:
            - Player records actions in a loop.
            - Next loop, a "ghost" (echo) replays those actions.
            - Cooperative puzzle: Use echoes to hold SWITCHES (opens matching DOORS) or block LASERS.
            - BLOCKS can be pushed and stop lasers.
            - Goal: Reach the GOAL object.

            TASK:
            Provide a concise, step-by-step strategic hint to beat this level. 
            Format it clearly with "Loop 1:", "Loop 2:", etc.
            Keep it under 100 words.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt
        });

        setHintText(response.text);
    } catch (error) {
        console.error(error);
        setHintText("Unable to contact the timeline database. Please try again later.");
    } finally {
        setLoadingHint(false);
    }
  };


  // ---- Render Helpers ----

  const formatTime = (ms: number) => (ms / 1000).toFixed(1);

  const level = LEVELS[currentLevelIdx];
  // Safety check: ensure we are rendering the state that matches the current level
  // This prevents flickering old state when level changes before initLevel effect runs
  const isStateReady = gameState && gameState.levelId === level.id;

  // Use level data for initial render or fallback
  const displayObjects = isStateReady ? gameState.dynamicObjects : level.layout;
  const displayPlayerPos = isStateReady ? gameState.playerPos : level.startPos;
  const displayStatus = isStateReady ? gameState.status : 'IDLE';

  // Mobile Control Button Component
  const ControlBtn = ({ dir, icon: Icon, color = "bg-slate-800" }: { dir?: Direction, icon: any, color?: string }) => (
    <button
      className={`${color} w-14 h-14 rounded-full flex items-center justify-center shadow-lg active:scale-95 active:bg-cyan-900 transition-all border border-slate-600`}
      onPointerDown={(e) => {
        e.preventDefault(); 
        if (dir) handleInput(dir);
      }}
    >
      <Icon className="text-slate-200 w-8 h-8" />
    </button>
  );

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 flex flex-col items-center justify-center p-4 touch-none select-none">

      {/* Header */}
      <div className="w-full max-w-4xl flex flex-col md:flex-row justify-between items-center md:items-end mb-4 md:mb-6">
        <div className="text-center md:text-left mb-2 md:mb-0">
           <h1 className="text-3xl md:text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-purple-500 mb-2">
             ECHOSHIFT
           </h1>
           <div className="flex justify-center md:justify-start gap-4 text-sm font-medium text-slate-400">
             <span className="flex items-center gap-1"><RotateCw size={14}/> Loop {gameState?.currentLoop || 1} / {level.maxEchoes + 1}</span>
             <span className="flex items-center gap-1 text-cyan-400"><Clock size={14}/> {formatTime(gameState?.timeRemaining || level.loopDuration)}s</span>
           </div>
        </div>
        <div className="text-center md:text-right">
            <h2 className="text-lg md:text-xl font-bold text-slate-100">{level.id}. {level.name}</h2>
            <p className="text-slate-500 text-xs md:text-sm max-w-xs">{level.description}</p>
        </div>
      </div>

      {/* Game Area Container for Scaling */}
      <div 
        ref={containerRef}
        className="relative group flex items-center justify-center"
        style={{ 
          width: level.gridWidth * TILE_SIZE, 
          height: level.gridHeight * TILE_SIZE,
          transform: `scale(${scale})`,
          transformOrigin: 'top center',
          marginBottom: (scale < 1) ? `-${(1 - scale) * level.gridHeight * TILE_SIZE}px` : '0px'
        }}
      >

        {/* Canvas */}
        <GameCanvas 
          level={level}
          width={level.gridWidth}
          height={level.gridHeight}
          objects={displayObjects}
          playerPos={displayPlayerPos}
          echoes={echoPositions}
        />

        {/* Hint Modal Overlay */}
        {showHint && (
            <div className="absolute inset-0 bg-slate-950/95 backdrop-blur-sm z-[60] flex flex-col items-center justify-center p-6 rounded-lg border border-slate-700 shadow-2xl animate-in fade-in zoom-in duration-200">
                <div className="w-full max-w-md">
                    <div className="flex justify-between items-center mb-4 border-b border-slate-800 pb-2">
                        <h3 className="text-cyan-400 font-bold flex items-center gap-2">
                            <Bot size={20} /> STRATEGY GUIDE
                        </h3>
                        <button onClick={() => setShowHint(false)} className="text-slate-500 hover:text-white">
                            <X size={20} />
                        </button>
                    </div>

                    {loadingHint ? (
                        <div className="flex flex-col items-center py-8 gap-4">
                            <Loader2 className="animate-spin text-cyan-500" size={32} />
                            <p className="text-slate-400 text-sm animate-pulse">Analyzing timeline probabilities...</p>
                        </div>
                    ) : (
                        <div className="prose prose-invert prose-sm max-h-64 overflow-y-auto">
                            <p className="whitespace-pre-wrap text-slate-300 leading-relaxed">{hintText}</p>
                        </div>
                    )}
                </div>
            </div>
        )}

        {/* Status Overlays */}
        {displayStatus === 'IDLE' && !showHint && (
          <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm flex flex-col items-center justify-center z-50 rounded-lg">
             <button 
                onClick={() => {
                    const newState = { ...gameState!, status: 'PLAYING' as const };
                    setGameState(newState);
                    stateRef.current = newState;
                }}
                className="bg-cyan-600 hover:bg-cyan-500 text-white px-8 py-3 rounded-full font-bold shadow-[0_0_20px_rgba(8,145,178,0.5)] flex items-center gap-2 transition-transform hover:scale-105"
             >
                <Play size={20} fill="currentColor" /> INITIATE LINK
             </button>
             <p className="mt-4 text-slate-400 text-sm">Use Arrow Keys or Tap Controls</p>
          </div>
        )}

        {displayStatus === 'WON' && !showHint && (
          <div className="absolute inset-0 bg-green-900/90 backdrop-blur-md flex flex-col items-center justify-center z-50 animate-in fade-in duration-300 rounded-lg">
             <Trophy size={64} className="text-yellow-400 mb-4 drop-shadow-[0_0_15px_rgba(250,204,21,0.5)]" />
             <h2 className="text-3xl font-bold text-white mb-2">COMPLETE</h2>
             <div className="flex gap-4">
               {currentLevelIdx < LEVELS.length - 1 ? (
                 <button 
                    onClick={() => {
                        setCurrentLevelIdx(prev => prev + 1);
                    }}
                    className="bg-white text-green-900 px-6 py-2 rounded-full font-bold hover:bg-green-100 flex items-center gap-2"
                 >
                    Next Level <SkipForward size={16} />
                 </button>
               ) : (
                 <div className="text-center">
                    <p className="text-xl font-bold text-white">ALL CLEAR</p>
                    <button 
                        onClick={() => setCurrentLevelIdx(0)}
                        className="mt-4 text-sm text-green-300 hover:text-white underline"
                    >
                        Restart
                    </button>
                 </div>
               )}
             </div>
          </div>
        )}

        {displayStatus === 'LOST' && !showHint && (
          <div className="absolute inset-0 bg-red-950/90 backdrop-blur-md flex flex-col items-center justify-center z-50 animate-in fade-in duration-300 rounded-lg">
             <Skull size={64} className="text-red-500 mb-4" />
             <h2 className="text-2xl font-bold text-white mb-2">FAILURE</h2>
             <p className="text-red-200 mb-6 text-center text-sm px-4">
                {gameState?.echoes.length! >= level.maxEchoes 
                  ? "Loop Limit Exceeded" 
                  : "Paradox Detected"}
             </p>
             <button 
                onClick={() => initLevel(currentLevelIdx)}
                className="bg-red-600 hover:bg-red-500 text-white px-6 py-2 rounded-full font-bold shadow-lg flex items-center gap-2"
             >
                <RefreshCw size={16} /> REBOOT
             </button>
          </div>
        )}
      </div>

      {/* Hint Button */}
      <button 
         onClick={fetchHint}
         className="mt-6 text-cyan-400 hover:text-cyan-300 font-bold text-lg flex items-center gap-2 transition-colors animate-pulse hover:animate-none"
      >
         How do I beat this level?
      </button>

      {/* Mobile Controls */}
      <div className="mt-6 grid grid-cols-3 gap-3">
        <div className="flex items-center justify-center">
            {/* Empty corner */}
        </div>
        <div className="flex items-center justify-center">
            <ControlBtn dir="UP" icon={ChevronUp} />
        </div>
        <div className="flex items-center justify-center">
            <button 
              className="w-12 h-12 rounded-full bg-slate-800 border border-slate-600 flex items-center justify-center active:bg-slate-700"
              onPointerDown={() => initLevel(currentLevelIdx)}
              aria-label="Reset Level"
            >
                <RotateCw size={20} className="text-slate-400" />
            </button>
        </div>

        <div className="flex items-center justify-center">
            <ControlBtn dir="LEFT" icon={ChevronLeft} />
        </div>
        <div className="flex items-center justify-center">
            <ControlBtn dir="WAIT" icon={Circle} color="bg-slate-700/50" />
        </div>
        <div className="flex items-center justify-center">
            <ControlBtn dir="RIGHT" icon={ChevronRight} />
        </div>

        <div className="flex items-center justify-center">
            {/* Empty corner */}
        </div>
        <div className="flex items-center justify-center">
            <ControlBtn dir="DOWN" icon={ChevronDown} />
        </div>
        <div className="flex items-center justify-center">
             {/* Empty corner */}
        </div>
      </div>

      {/* HUD Footer (Visual Only now) */}
      <div className="w-full max-w-4xl mt-6 flex justify-between items-center px-4">
         <div className="flex gap-2">
            {Array.from({ length: level.maxEchoes + 1 }).map((_, i) => {
                const isCurrent = (gameState?.currentLoop || 1) === i + 1;
                const isPast = (gameState?.currentLoop || 1) > i + 1;
                return (
                    <div key={i} className={`h-2 w-8 md:w-12 rounded-full transition-colors ${
                        isCurrent ? 'bg-cyan-400 shadow-[0_0_10px_#22d3ee]' : 
                        isPast ? 'bg-purple-500' : 'bg-slate-800'
                    }`} />
                );
            })}
         </div>

         <div className="hidden md:flex gap-6 text-xs text-slate-500">
            <div className="flex items-center gap-2">
                <span className="font-bold text-slate-400">ARROWS</span> Move
            </div>
            <div className="flex items-center gap-2">
                <span className="font-bold text-slate-400">SPACE</span> Wait
            </div>
            <div className="flex items-center gap-2">
                <span className="font-bold text-slate-400">R</span> Reset
            </div>
         </div>
      </div>

      {/* Timer Bar */}
      <div className="fixed bottom-0 left-0 h-1 bg-cyan-500 transition-all duration-75 ease-linear" 
           style={{ width: `${((gameState?.timeRemaining || 0) / level.loopDuration) * 100}%` }} 
      />

    </div>
  );
};

export default App;
